INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (2, "2024/10/31 12:00:00", "ヤマト", "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか", 3001100, 130011, 2.1, 1, -416.5, 0.0, "2030/01/01 14:59:59", 100, 3001);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (2, "2024/10/31 12:00:00", "ヤマト", "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか", 3001101, 130011, 5.68, 4, -416.5, 0.0, "2030/01/01 14:59:59", 101, 3001);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (1, "2024/10/31 12:00:00", "ヤマト", "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。", 3001102, 130011, 0.0, 1, -416.5, 0.0, "2030/01/01 14:59:59", 102, 3001);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (1, "2024/10/31 12:00:00", "フブキ", "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？", 3002100, 130211, 0.0, 1, -416.5, 0.0, "2030/01/01 14:59:59", 100, 3002);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (1, "2024/10/31 12:00:00", "フブキ", "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡", 3002101, 130211, 0.0, 1, -416.5, 0.0, "2030/01/01 14:59:59", 101, 3002);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (2, "2024/10/31 12:00:00", "フブキ", "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ", 3002102, 130211, 8.53, 5, -416.5, 0.0, "2030/01/01 14:59:59", 102, 3002);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (1, "2024/10/31 12:00:00", "フブキ", "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？", 3002103, 130211, 5.67, 7, -416.5, 0.0, "2030/01/01 14:59:59", 103, 3002);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (1, "2024/10/31 12:00:00", "フブキ", "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？", 3002104, 130211, 0.0, 1, -416.5, 0.0, "2030/01/01 14:59:59", 104, 3002);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (3, "2024/10/31 12:00:00", "フブキ", "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？", 3002300, 130211, 0.0, 3, -416.5, 0.0, "2030/01/01 14:59:59", 300, 3004);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (7, "2024/10/31 12:00:00", "フブキ", "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡", 3002400, 130211, 0.0, 7, -416.5, 0.0, "2030/01/01 14:59:59", 301, 3005);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (1, "2024/10/31 12:00:00", "フブキ", "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪", 3003200, 130211, 4.4, 2, -416.5, 0.0, "2030/01/01 14:59:59", 200, 3003);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (7, "2024/10/31 12:00:00", "フブキ", "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ", 3003201, 130211, 0.0, 7, -416.5, 0.0, "2030/01/01 14:59:59", 201, 3003);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (2, "2024/10/31 12:00:00", "フブキ", "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪", 3003202, 130211, 5.6, 1, -416.5, 0.0, "2030/01/01 14:59:59", 202, 3003);
